{"code":"import json
import re

# Load UC patent records again to get pub numbers
# Key for the file containing UC patents
uc_file_path = locals()['var_function-call-15762675750983783495']
with open(uc_file_path, 'r') as f:
    uc_records = json.load(f)

uc_pub_nums = set()
for rec in uc_records:
    info = rec['Patents_info']
    match = re.search(r'(?:publication|pub\.?)\s+(?:number|no\.?)\s+([A-Z]{2}-[0-9A-Z]+-[A-Z0-9]+)', info)
    if match:
        uc_pub_nums.add(match.group(1))

# Load all patents
all_patents_path = locals()['var_function-call-3142653111375801446']
with open(all_patents_path, 'r') as f:
    all_patents = json.load(f)

results = []

def extract_assignee(text):
    text = text.replace('\n', ' ')
    # "X holds the"
    match = re.search(r'^(.*?)\s+holds\s+the', text)
    if match: return match.group(1).strip()
    # "is owned by X and" / "is assigned to X and"
    match = re.search(r'is\s+(?:owned|assigned|belonging|held)\s+(?:by|to)\s+(.*?)\s+(?:and|with)', text)
    if match: return match.group(1).strip()
    # "owned by X, with" / "belonging to X, with"
    match = re.search(r'(?:owned|assigned|belonging|held)\s+(?:by|to)\s+(.*?)(?:,|\s+with)', text)
    if match: return match.group(1).strip()
    return None

for rec in all_patents:
    assignee = extract_assignee(rec['Patents_info'])
    if not assignee or "UNIV CALIFORNIA" in assignee:
        continue

    citations_str = rec.get('citation')
    if not citations_str or len(citations_str) < 5:
        continue

    try:
        citations = json.loads(citations_str)
    except:
        continue

    # Check if cites UC
    cites_uc = False
    for cit in citations:
        if cit.get('publication_number') in uc_pub_nums:
            cites_uc = True
            break

    if cites_uc:
        cpc_str = rec.get('cpc')
        subclass = None
        if cpc_str and len(cpc_str) > 5:
            try:
                cpcs = json.loads(cpc_str)
                if cpcs and isinstance(cpcs, list) and len(cpcs) > 0:
                    code = cpcs[0].get('code')
                    if code and len(code) >= 4:
                        subclass = code[:4]
            except:
                pass

        if subclass:
            results.append({"assignee": assignee, "subclass": subclass})

# Deduplicate
unique_results = []
seen = set()
for r in results:
    key = (r['assignee'], r['subclass'])
    if key not in seen:
        seen.add(key)
        unique_results.append(r)

print("__RESULT__:")
print(json.dumps(unique_results))
"}

